insert into public.products
  (sku, handle, title, category_slug, manifest, condition, retail_value_usd, price_usd, units, cost_per_unit_usd, availability, images, summary, sort_order)
values
('G51490', '4x4-picture-frames-90-off-original-retail-g51490', '4x6" & 8x10" Picture Frames : 92% Off Original Retail (G51490)', 'houseware', 'unmanifested', 'mos', 6875, 550, 224, 2.46, 'in-stock', array['/images/products/G51490-1.webp','/images/products/G51490-2.webp'], 'Unmanifested houseware lot of 4x6 and 8x10 picture frames in past-season transfer condition, totaling 224 units at a landed cost of $2.46 per unit. Retail value runs $6,875 against a $550 buy, so margin headroom is built in once the lot is sorted by size and finish. Frames move well for dollar stores, flea markets, gift shops, and Amazon/eBay flips priced at the $5 to $15 sweet spot, and they also pull steady traffic at weekend markets and yard-sale resellers. On intake, separate by size first, then pull any glass-cracked units to the side for parts or bundled lots before listing the clean inventory.', 0),
('G59754', 'assorted-bedding-82-off-original-retail-g59754', 'Assorted Bedding: 92% Off Original Retail (G59754)', 'houseware', 'unmanifested', 'mos', 4898.67, 391.89, 88, 4.45, 'in-stock', array['/images/products/G59754-1.webp','/images/products/G59754-2.webp'], 'Mixed bedding pallet of 88 units in past-season transfer condition, unmanifested, with a retail value near $4,898.67 priced at $391.89 for a $4.45 per-unit cost. Expect a spread of sheet sets, pillowcases, and similar soft goods that resellers can list across eBay, Mercari, Poshmark, and Facebook Marketplace, while flea-market and discount-store buyers will take the volume in bulk. Per-unit cost gives room to price aggressively while still hitting healthy margin on the larger sets. On intake, sort by size first (twin, queen, king), then by color group so listings and bundles come together fast at the dock.', 1),
('G59763', 'assorted-bedding-82-off-original-retail-g59763', 'Assorted Bedding: 92% Off Original Retail (G59763)', 'houseware', 'unmanifested', 'mos', 2790, 223.2, 45, 4.96, 'in-stock', array['/images/products/G59763-1.webp','/images/products/G59763-2.webp'], 'Smaller assorted bedding lot of 45 unmanifested units in past-season transfer condition, retailing at $2,790 and offered at $223.20, which lands the cost at $4.96 per unit. Mix should cover a range of sheet sets and soft-good basics suited to discount retailers, flea-market booths, and online resellers running per-piece listings on eBay, Mercari, or Poshmark. The compact unit count is workable for a single reseller who wants test inventory without committing to a full truckload of soft goods. On intake, separate by size and pull any opened or repackaged retail packaging into a clearance sub-lot to keep the main inventory cleanly listable.', 2),
('G59775', 'assorted-bedding-82-off-original-retail-g59775', 'Assorted Bedding: 92% Off Original Retail (G59775)', 'houseware', 'unmanifested', 'mos', 2700, 216, 50, 4.32, 'in-stock', array['/images/products/G59775-1.webp','/images/products/G59775-2.webp'], 'Assorted bedding pallet of 50 unmanifested units in past-season transfer condition, $2,700 retail against a $216 buy, working out to $4.32 per unit. Expect a working mix of sheet sets and soft goods that resellers can move through eBay, Mercari, Facebook Marketplace, and weekend flea booths, with per-piece pricing typically clearing several times the landed cost. The low unit count is friendly for a smaller reseller testing the category or topping up an existing soft-goods rack. On intake, sort by size and color first, then bundle any odd singles into mixed-color value packs so nothing sits as dead stock.', 3),
('G59783', 'assorted-bedding-82-off-original-retail-g59783', 'Assorted Bedding: 92% Off Original Retail (G59783)', 'houseware', 'unmanifested', 'mos', 2793, 223.44, 57, 3.92, 'in-stock', array['/images/products/G59783-1.webp','/images/products/G59783-2.webp'], 'Pallet of 57 unmanifested bedding units in past-season transfer condition, with a $2,793 retail tag listed at $223.44, landing each piece at $3.92. Mix should include sheet sets, pillowcases, and related soft goods that move steadily through discount retailers, flea booths, and per-piece online listings on eBay, Mercari, and Poshmark. The sub-$4 per-unit cost gives room to bundle multi-piece sets or split them into singles depending on what your channel pays best. On intake, sort by size and pull anything with damaged retail packaging into a B-grade sub-lot before the clean inventory hits the listing queue.', 4),
('G59787', 'assorted-bedding-82-off-original-retail-g59787', 'Assorted Bedding: 92% Off Original Retail (G59787)', 'houseware', 'unmanifested', 'mos', 1666, 133.28, 34, 3.92, 'in-stock', array['/images/products/G59787-1.webp','/images/products/G59787-2.webp'], 'Smaller assorted bedding lot of 34 unmanifested units in past-season transfer condition, $1,666 retail at $133.28, costing $3.92 per piece. Expect a working mix of sheet sets and soft goods suited to flea-market booths, discount-store top-offs, and online resellers running per-item listings on eBay and Mercari. With only 34 units, this is a fit for a smaller operator who wants to test the category or fill out an existing soft-goods section without committing to a larger truckload. On intake, separate by size first, then group by color so multi-piece sets and bundled listings can be staged quickly at the dock.', 5),
('G59791', 'assorted-bedding-82-off-original-retail-g59791', 'Assorted Bedding: 92% Off Original Retail (G59791)', 'houseware', 'unmanifested', 'mos', 1960, 156.8, 40, 3.92, 'in-stock', array['/images/products/G59791-1.webp','/images/products/G59791-2.webp'], 'Unmanifested bedding pallet of 40 units in past-season transfer condition, retailing at $1,960 and offered at $156.80 for a $3.92 per-unit cost. Mix should fall across sheet sets, pillowcases, and related soft goods that work for flea-market sellers, discount retailers, and online flips through eBay, Mercari, and Facebook Marketplace. Per-unit pricing leaves clear margin headroom whether you list individually or build multi-piece bundles for higher ticket sizes. On intake, sort by size and color, then keep any units with retail tags still attached together so they can be listed at a premium versus loose pieces.', 6),
('G59793', 'assorted-bedding-82-off-original-retail-g59793', 'Assorted Bedding: 92% Off Original Retail (G59793)', 'houseware', 'unmanifested', 'mos', 1960, 156.8, 40, 3.92, 'in-stock', array['/images/products/G59793-1.webp','/images/products/G59793-2.webp'], 'Assorted bedding lot of 40 unmanifested units in past-season transfer condition, $1,960 retail against a $156.80 buy, working out to $3.92 each. Expect a working mix of sheet sets and related soft goods that resellers can move through eBay, Mercari, Poshmark, flea booths, and discount-store channels at per-piece prices well above the landed cost. The compact unit count makes it a clean fit for smaller operators or for buyers topping up an existing soft-goods inventory without overcommitting. On intake, separate by size first, then by color group, and pull any loose or damaged retail packaging into a B-grade sub-lot before listings go live.', 7),
('G59794', 'assorted-bedding-82-off-original-retail-g59794', 'Assorted Bedding: 92% Off Original Retail (G59794)', 'houseware', 'unmanifested', 'mos', 2205, 176.4, 45, 3.92, 'in-stock', array['/images/products/G59794-1.webp','/images/products/G59794-2.webp'], 'Unmanifested bedding pallet of 45 units in past-season transfer condition, $2,205 retail listed at $176.40, which lands the cost at $3.92 per unit. The mix should run across sheet sets, pillowcases, and soft goods that move well through flea-market booths, discount retailers, and per-piece online listings on eBay, Mercari, and Facebook Marketplace. Margin headroom is solid whether you split into singles or rebuild multi-piece bundles for a higher ticket. On intake, sort by size first, then group by color and pull retail-tagged units to the front of the listing queue so the highest-value pieces clear the dock first.', 8),
('G51326', 'assorted-books-90-off-original-retail-g51326', 'Assorted Books: 90% Off Original Retail (G51326)', 'general-merchandise', 'unmanifested', 'mos', 31225.4, 3122.54, 1566, 1.99, 'in-stock', array['/images/products/G51326-1.webp','/images/products/G51326-2.webp'], 'Heavy unmanifested book lot of 1,566 units in past-season transfer condition, $31,225.40 retail against a $3,122.54 buy, landing each book at $1.99. Mixed-title lots like this move through used bookstores, Amazon FBA sellers running ISBN scans, weekend flea booths, library Friends-of sales, and bulk online flips, where decent finds easily clear several times the landed cost. The volume here suits an operator with shelf space and an ISBN-scanning workflow rather than a casual flipper. On intake, run the full pallet through a scan app first, pull anything that ranks under 1M sales rank for FBA, and route the balance to bulk channels or per-pound resale.', 9),
('G51353', 'assorted-books-90-off-original-retail-g51353', 'Assorted Books: 90% Off Original Retail (G51353)', 'general-merchandise', 'unmanifested', 'mos', 25324.83, 2532.48, 1263, 2.01, 'in-stock', array['/images/products/G51353-1.webp','/images/products/G51353-2.webp'], 'Unmanifested book pallet of 1,263 units in past-season transfer condition, $25,324.83 retail at $2,532.48, landing each piece at $2.01. Mixed-title book lots reward operators with an ISBN-scan workflow: Amazon FBA sellers, used bookstores, weekend booths, and bulk online resellers all draw from this kind of inventory, with strong individual finds clearing well above the per-unit cost. Volume makes this a fit for buyers with sortable shelf or rack space rather than casual flippers. On intake, scan the whole pallet first, route low-rank titles to FBA, group genre clusters for online lots, and clear the long tail to per-pound bulk buyers.', 10),
('G51651', 'assorted-books-90-off-original-retail-g51651', 'Assorted Books: 90% Off Original Retail (G51651)', 'general-merchandise', 'unmanifested', 'mos', 19541.07, 1954.11, 1154, 1.69, 'in-stock', array['/images/products/G51651-1.webp','/images/products/G51651-2.webp'], 'Unmanifested book lot of 1,154 units in past-season transfer condition, $19,541.07 retail offered at $1,954.11, which puts each book at $1.69 landed. The mix should yield the usual blend of fiction, nonfiction, and reference titles that feed used bookstores, Amazon FBA scanners, library sales, and bulk online flippers, with high-rank finds clearing several multiples above cost. The sub-$2 per-unit price gives extra room to absorb the long-tail titles that always come with mixed-book pallets. On intake, run every book through an ISBN scan app, pull FBA candidates first, group the rest by genre for lot listings, and send the balance to per-pound bulk channels.', 11),
('G51337', 'assorted-candles-90-off-original-retail-g51337', 'Assorted Candles: 92% Off Original Retail (G51337)', 'houseware', 'unmanifested', 'mos', 12542.5, 1003.4, 781, 1.28, 'in-stock', array['/images/products/G51337-1.webp','/images/products/G51337-2.webp'], 'Unmanifested candle pallet of 781 units in past-season transfer condition, $12,542.50 retail listed at $1,003.40, landing each candle at $1.28. Mixed candle lots move quickly through gift shops, dollar stores, flea-market booths, Amazon and eBay flippers, and seasonal pop-up retailers, with per-piece pricing in the $3 to $10 range easily clearing several multiples of cost. The low per-unit landed price leaves plenty of room to bundle scents or sizes for higher-ticket gift sets. On intake, sort by size, then by scent family, and pull any units with damaged wax or labels into a clearance sub-lot before the clean inventory hits the listing queue.', 12),
('ARP201', 'assorted-clothing-82-off-original-retail-arp201', 'Assorted Clothing: 82% Off Original Retail (ARP201)', 'apparel', 'unmanifested', 'mos', 41543.74, 7477.87, 3228, 2.32, 'in-stock', array['/images/products/ARP201-1.webp','/images/products/ARP201-2.webp'], 'Large apparel pallet of 3,228 unmanifested units in past-season transfer condition, $41,543.74 retail against a $7,477.87 buy, landing each piece at $2.32. Expect a working mix of soft-goods apparel that feeds flea-market booths, weekend swap-meet sellers, export buyers, thrift-style storefronts, and per-piece Poshmark and Mercari flippers, with even modest sell-through clearing multiple times the per-unit cost. Volume makes this a fit for operators with sorting space and a clear downstream channel rather than a single-listing flipper. On intake, sort by gender and category first, then size, and route any retail-tagged or like-new pieces to online channels while the balance moves to bulk per-piece resale.', 13),
('G59750', 'assorted-comforters-82-off-original-retail-g59750', 'Assorted Comforters: 92% Off Original Retail (G59750)', 'houseware', 'unmanifested', 'mos', 2977, 238.16, 13, 18.32, 'in-stock', array['/images/products/G59750-1.webp','/images/products/G59750-2.webp'], 'Compact unmanifested comforter lot of 13 units in past-season transfer condition, $2,977 retail offered at $238.16, which lands each comforter at $18.32. Comforters carry a higher individual ticket than sheet sets and move well through flea-market booths, Facebook Marketplace, eBay, and discount-store top-offs, where per-piece pricing in the $40 to $80 range still clears a comfortable spread over landed cost. The small unit count makes this a clean fit for a single reseller testing the category or filling out a soft-goods display. On intake, sort by size first, then by style, and stage retail-tagged pieces for priority listing at the front of the queue.', 14),
('G59757', 'assorted-comforters-82-off-original-retail-g59757', 'Assorted Comforters: 92% Off Original Retail (G59757)', 'houseware', 'unmanifested', 'mos', 3435, 274.8, 15, 18.32, 'in-stock', array['/images/products/G59757-1.webp','/images/products/G59757-2.webp'], 'Unmanifested lot of 15 assorted comforters graded Past Season Transfers, pulled from prior-season home textile programs in the Houseware category. At $274.80 for the lot and roughly $18.32 per unit against a $3,435 retail tag, the math works for flea-market booths, discount bedding shops, and Facebook Marketplace flippers who can move bulky soft goods one piece at a time. Past-season pieces still photograph well online once unboxed and steamed, which is where most of the per-unit margin lives. On intake, open the pallet under cover, sort by size, and bag individually before staging to keep dust and floor scuffs off the shells.', 15),
('G59758', 'assorted-comforters-82-off-original-retail-g59758', 'Assorted Comforters: 92% Off Original Retail (G59758)', 'houseware', 'unmanifested', 'mos', 3435, 274.8, 15, 18.32, 'in-stock', array['/images/products/G59758-1.webp','/images/products/G59758-2.webp'], 'Second pallet in the comforter run, again 15 units of Past Season Transfers from the Houseware category, unmanifested and priced at $274.80, or about $18.32 per unit against $3,435 in stated retail. This is a straightforward resale flip for bedding resellers, weekend market vendors, and small home-decor shops that need cover-bed inventory at a single-digit landed cost after freight. Past-season patterns sell faster when paired with a sham or throw at checkout, so consider bundling. On intake, inspect for factory-fold creases versus actual damage, and stage the cleanest pieces for online listings while routing the rest to in-person channels.', 16),
('G59759', 'assorted-comforters-82-off-original-retail-g59759', 'Assorted Comforters: 92% Off Original Retail (G59759)', 'houseware', 'unmanifested', 'mos', 3435, 274.8, 15, 18.32, 'in-stock', array['/images/products/G59759-1.webp','/images/products/G59759-2.webp'], 'Third matching pallet of 15 assorted comforters, Past Season Transfers grade, unmanifested Houseware stock priced at $274.80 for the lot and $18.32 per unit against $3,435 retail. Stack-buying all three G597xx pallets gives a small bedding reseller 45 covers to anchor a booth, a discount linen aisle, or a seasonal pop-up at one consistent per-unit cost. Because the assortment is unmanifested, plan on a quick mix of sizes and colorways rather than matched sets. Break the pallet down on a clean table, photograph each piece against a neutral backdrop, and list immediately while the season-shift demand window is open.', 17),
('G51235', 'assorted-cosmetics-90-off-original-retail-g51235', 'Assorted Cosmetics: 92% Off Original Retail (G51235)', 'health-beauty', 'unmanifested', 'mos', 61840.97, 4947.28, 1911, 2.59, 'in-stock', array['/images/products/G51235-1.webp','/images/products/G51235-2.webp'], 'Large unmanifested cosmetics pallet in the Health and Beauty category, 1,911 units graded Past Season Transfers and priced at $4,947.28, which works out to roughly $2.59 per unit against $61,840.97 in stated retail. The volume and per-unit math suit dollar-store buyers, beauty supply resellers, and discount drug operators who can sell single SKUs through the register without a manifest. Past-season cosmetics still move well at impulse price points once organized by category. On intake, sort first by product type (face, lip, eye, nail), pull anything with broken seals or expired-looking packaging to a damage bin, and box the keepers by category for shelf-ready trays.', 18),
('G51777', 'assorted-cosmetics-90-off-original-retail-g51777', 'Assorted Cosmetics: 92% Off Original Retail (G51777)', 'health-beauty', 'partially', 'mos', 20115, 1609.2, 1878, 0.86, 'in-stock', array['/images/products/G51777-1.webp','/images/products/G51777-2.webp'], 'Partially manifested Health and Beauty lot of 1,878 cosmetic units graded Past Season Transfers, priced at $1,609.20, or about $0.86 per unit against $20,115 retail. Sub-dollar landed cost is the headline for bin-store operators, dollar resellers, and beauty supply shops running mix-and-match tables, because nearly any single sell-through covers the cost of the piece. The partial manifest is useful for pulling higher-ticket items to feature, while the rest fills out grab-bag bins. On intake, cross-check the manifest first, pull the called-out SKUs to a separate tote for online listing, and route the unmanifested balance straight to floor bins.', 19),
('G58187', 'assorted-dish-towels-82-off-original-retail-g58187', 'Assorted Dish Towels: 85% Off Original Retail (G58187)', 'houseware', 'unmanifested', 'first-quality', 23304, 3495.6, 971, 3.6, 'in-stock', array['/images/products/G58187-1.webp','/images/products/G58187-2.webp'], 'First Quality dish towel pallet in the Houseware category, 971 unmanifested units priced at $3,495.60, or about $3.60 per unit against $23,304 retail. First-quality grading means these are not seconds or returns, which opens up channels that other liquidation lots cannot serve: gift shops, home goods stores, kitchen supply resellers, and Amazon/eBay flippers who need clean inventory for new-condition listings. Dish towels move year-round and bundle well into three-packs at checkout. On intake, open a sample carton to confirm pattern mix, sort by colorway, and shrink-wrap small bundles ahead of staging to speed up retail handoff.', 20),
('G58444', 'assorted-dish-towels-82-off-original-retail-g58444', 'Assorted Dish Towels: 85% Off Original Retail (G58444)', 'houseware', 'unmanifested', 'mos', 25693.33, 3854, 940, 4.1, 'in-stock', array['/images/products/G58444-1.webp','/images/products/G58444-2.webp'], 'Unmanifested Houseware pallet of 940 assorted dish towels graded Past Season Transfers, priced at $3,854, which lands around $4.10 per unit against $25,693.33 in stated retail. The volume fits flea vendors, discount home stores, and online resellers who can move kitchen textiles in three- and four-pack bundles. Past-season prints still sell briskly when staged on an end-cap or photographed flat for marketplace listings. On intake, run a quick visual pass for stains or factory marks, separate seasonal or holiday prints to hold for the right calendar window, and bundle everyday patterns into ready-to-tag retail packs straight off the dock.', 21),
('G58485', 'assorted-dish-towels-82-off-original-retail-g58485', 'Assorted Dish Towels: 85% Off Original Retail (G58485)', 'houseware', 'unmanifested', 'mos', 32412, 4861.8, 1414, 3.44, 'in-stock', array['/images/products/G58485-1.webp','/images/products/G58485-2.webp'], 'Larger unmanifested dish towel pallet, 1,414 units of Past Season Transfers in the Houseware category, priced at $4,861.80, or about $3.44 per unit against $32,412 retail. The deeper unit count rewards buyers who already have a dish-towel program running and need to refill bins fast, including discount home stores, dollar-plus operators, and multi-booth flea vendors. Past-season prints sell as everyday utility goods once the seasonal tags come off. On intake, weigh and count a sample carton to confirm the unit average, group prints into solid versus printed lanes, and bundle into three-packs to lift the per-ring ticket at retail.', 22),
('G58497', 'assorted-dish-towels-82-off-original-retail-g58497', 'Assorted Dish Towels: 85% Off Original Retail (G58497)', 'houseware', 'unmanifested', 'mos', 38178, 5726.7, 1701, 3.37, 'in-stock', array['/images/products/G58497-1.webp','/images/products/G58497-2.webp'], 'Largest of the dish-towel pallets, 1,701 unmanifested Past Season Transfers units in the Houseware category, priced at $5,726.70 against $38,178 retail at roughly $3.37 per unit. The combination of low per-unit cost and high unit count suits high-velocity resellers: bin stores, off-price chains running open-stock tables, and Amazon FBA sellers who can bundle into multi-packs and ship pallet-loads through one ASIN. Bulk dish towels are forgiving inventory that does not age out quickly. On intake, palletize by print family, set aside any damaged or open-pack pieces for a clearance bin, and stage the clean balance for direct retail flow.', 23),
('G50763', 'assorted-floral-garlands-82-off-original-retail-g50763', 'Assorted Floral Garlands: 82% Off Original Retail (G50763)', 'general-merchandise', 'unmanifested', 'mos', 13200, 2376, 360, 6.6, 'in-stock', array['/images/products/G50763-1.webp','/images/products/G50763-2.webp'], 'Unmanifested General Merchandise pallet of 360 assorted floral garlands graded Past Season Transfers, priced at $2,376, which is about $6.60 per unit against $13,200 retail. Floral garlands are seasonal decor staples for craft resellers, party rental operators, wedding stagers, and event-prop flippers, all of whom can absorb 360 units across a few months of bookings. Past-season styles read as on-trend once restyled in a fresh arrangement or photo. On intake, hang or coil each piece to release packing creases, sort by floral type and color family, and store flat in shallow totes so blooms keep their shape through the next event cycle.', 24),
('G58138', 'assorted-garden-products-82-off-original-retail-g58138', 'Assorted Garden Products: 90% Off Original Retail (G58138)', 'general-merchandise', 'unmanifested', 'first-quality', 3847.5, 384.75, 95, 4.05, 'in-stock', array['/images/products/G58138-1.webp','/images/products/G58138-2.webp'], 'Compact First Quality garden lot in the General Merchandise category, 95 unmanifested units priced at $384.75, or about $4.05 per unit against $3,847.50 retail. First-quality grading and a small unit count make this lot a good fit for independent garden centers, hardware stores, and weekend market vendors who want clean inventory without committing to a full truckload. Garden goods sell on impulse during the active season, especially when staged outside the door. On intake, unpack on a tarp to keep soil and packing debris contained, sort by category (tools, decor, pots, accents), and price-tag immediately so the lot can move straight to a sidewalk or end-cap display.', 25),
('G51645', 'assorted-garden-products-90-off-original-retail-g51645', 'Assorted Garden Products: 92% Off Original Retail (G51645)', 'general-merchandise', 'unmanifested', 'mos', 9146.5, 731.72, 360, 2.03, 'in-stock', array['/images/products/G51645-1.webp','/images/products/G51645-2.webp'], 'Unmanifested General Merchandise garden pallet, 360 units of Past Season Transfers priced at $731.72, or roughly $2.03 per unit against $9,146.50 retail. Sub-three-dollar landed cost gives resellers room to price aggressively while still clearing strong margins through dollar-plus channels, flea markets, and discount hardware aisles. Past-season garden goods sell as steady utility inventory once seasonal tags are removed. On intake, separate fragile items (ceramic, glass, resin) from hard goods, pull any pieces with cracked packaging to a clearance bin, and stage the rest by category so shoppers can browse the lot like a built-out garden aisle.', 26),
('G51712', 'assorted-garden-products-90-off-original-retail-g51712', 'Assorted Garden Products: 92% Off Original Retail (G51712)', 'general-merchandise', 'unmanifested', 'mos', 9977.5, 798.2, 471, 1.69, 'in-stock', array['/images/products/G51712-1.webp','/images/products/G51712-2.webp'], 'Larger unmanifested General Merchandise garden pallet of 471 Past Season Transfers units, priced at $798.20, or about $1.69 per unit against $9,977.50 retail. The deep unit count and very low per-unit cost favor bin-store operators, market vendors, and discount garden centers that price by piece and need volume to fill tables. Past-season garden inventory carries year-round at impulse price points, especially small decor and accessory SKUs. On intake, weigh and count a sample carton to baseline the mix, separate breakables, and route hard-goods directly to floor bins while holding decorative or themed pieces for the matching seasonal push.', 27),
('G51322', 'assorted-phone-cases-90-off-original-retail-g51322', 'Assorted iPhone Cases: 92% Off Original Retail (G51322)', 'electronics', 'unmanifested', 'mos', 55268.5, 4421.48, 2219, 1.99, 'in-stock', array['/images/products/G51322-1.webp','/images/products/G51322-2.webp'], 'Unmanifested Consumer Electronics pallet of 2,219 assorted iPhone Cases graded Past Season Transfers, priced at $4,421.48, which lands near $1.99 per unit against $55,268.50 retail. Phone cases are one of the most forgiving impulse SKUs in liquidation: kiosk operators, swap-meet vendors, repair shops, and online accessory resellers can sell single pieces at retail price points that clear cost on the first ring. Past-season models still move because compatible handsets stay in market for years. On intake, sort by handset model first, then by style, and bag damaged or unbranded pieces separately for a clearance peg.', 28),
('G51342', 'assorted-phone-cases-90-off-original-retail-g51342', 'Assorted iPhone Cases: 92% Off Original Retail (G51342)', 'electronics', 'unmanifested', 'mos', 27448, 2195.84, 1022, 2.15, 'in-stock', array['/images/products/G51342-1.webp','/images/products/G51342-2.webp'], 'Second iPhone case pallet, unmanifested Consumer Electronics stock of 1,022 units graded Past Season Transfers, priced at $2,195.84, or about $2.15 per unit against $27,448 retail. Smaller unit count makes this lot easier to absorb for a single kiosk, repair shop, or accessory booth that does not have room for a 2,000-piece pallet. Cases sell on impulse at the counter and online as quick-shipping eBay or Amazon listings. On intake, sort by handset compatibility before anything else, peg-display the cleanest pieces on a slatwall, and route the rest to a bulk bin priced flat for walk-in shoppers.', 29),
